{
    "level": "B1",
    "intro": "In this topic, you will learn in detail <strong>Present Perfect Passive</strong>: how to form this form, when to use it and how it differs from other passive tenses.",
    "rules": [
        {
            "label": "Formula",
            "color": "emerald",
            "text": "<strong>Subject + has/have + been + V3</strong>:",
            "example": "The work has been completed."
        },
        {
            "label": "Denial",
            "color": "rose",
            "text": "<strong>Subject + has/have + not + been + V3</strong>:",
            "example": "The letter has not been sent yet."
        },
        {
            "label": "Question",
            "color": "blue",
            "text": "<strong>Has/Have + Subject + been + V3?</strong>:",
            "example": "Has the project been finished?"
        }
    ]
}

{
    "title": "1. Structure of the Present Perfect Passive",
    "intro": "The choice of <strong>has/have</strong> depends on the subject, while <strong>been</strong> remains the same:",
    "items": [
        {
            "label": "I/You/We/They",
            "title": "have been + V3",
            "subtitle": "The documents have been signed. — The documents are signed."
        },
        {
            "label": "He/She/It",
            "title": "has been + V3",
            "subtitle": "The report has been submitted. — The report has been submitted."
        },
        {
            "label": "Plural",
            "title": "have been + V3",
            "subtitle": "All tasks have been completed. - All tasks are completed."
        },
        {
            "label": "Key",
            "title": "been is the constant part",
            "subtitle": "been always precedes V3."
        }
    ]
}

{
    "title": "2. Affirmative sentences",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Word order: <strong>Subject + has/have + been + V3 (+ by agent)</strong>",
            "examples": [
                {
                    "en": "The project has been completed successfully.",
                    "ua": "The project has been completed successfully."
                },
                {
                    "en": "All the tickets have been sold.",
                    "ua": "All the tickets have been sold."
                },
                {
                    "en": "The problem has been solved.",
                    "ua": "The problem has been solved."
                },
                {
                    "en": "New rules have been introduced.",
                    "ua": "New rules have been introduced."
                }
            ]
        },
        {
            "label": "Focus on the result",
            "color": "sky",
            "description": "When the <strong>result</strong> is important, not the process:",
            "examples": [
                {
                    "en": "The email has been sent. (результат: лист відправлено)",
                    "ua": "The email has been sent. (результат: лист відправлено)"
                },
                {
                    "en": "The decision has been made. (результат: рішення прийнято)",
                    "ua": "The decision has been made. (результат: рішення прийнято)"
                },
                {
                    "en": "The repair has been done. (результат: ремонт зроблено)",
                    "ua": "The repair has been done. (результат: ремонт зроблено)"
                }
            ]
        }
    ]
}

{
    "title": "3. When to use Present Perfect Passive?",
    "sections": [
        {
            "label": "Completed actions with results",
            "color": "emerald",
            "description": "For actions that have <strong>completed</strong> and the result is <strong>important now</strong>:",
            "examples": [
                {
                    "en": "The report has been finished. (готово до перегляду)",
                    "ua": "The report has been finished. (готово до перегляду)"
                },
                {
                    "en": "Your application has been approved.",
                    "ua": "Your application has been approved."
                },
                {
                    "en": "The system has been updated.",
                    "ua": "The system has been updated."
                }
            ]
        },
        {
            "label": "Recent actions",
            "color": "blue",
            "description": "For actions that <strong>just happened</strong> (just, recently):",
            "examples": [
                {
                    "en": "The email has just been sent.",
                    "ua": "The email has just been sent."
                },
                {
                    "en": "The meeting has recently been scheduled.",
                    "ua": "The meeting has recently been scheduled."
                },
                {
                    "en": "New software has just been installed.",
                    "ua": "New software has just been installed."
                }
            ]
        },
        {
            "label": "Actions up to this point",
            "color": "amber",
            "description": "To describe what has been <strong>done/not done so far</strong> (already, yet, ever, never):",
            "examples": [
                {
                    "en": "The file has already been uploaded.",
                    "ua": "The file has already been uploaded."
                },
                {
                    "en": "The payment has not been received yet.",
                    "ua": "The payment has not been received yet."
                },
                {
                    "en": "Has this book ever been translated?",
                    "ua": "Has this book ever been translated?"
                }
            ]
        },
        {
            "label": "Period until now",
            "color": "rose",
            "description": "For actions during a <strong>period of time</strong> that includes the present moment (today, this week, since, for):",
            "examples": [
                {
                    "en": "Many changes have been made this year.",
                    "ua": "Many changes have been made this year."
                },
                {
                    "en": "The building has been renovated since 2020.",
                    "ua": "The building has been renovated since 2020."
                },
                {
                    "en": "Three emails have been sent today.",
                    "ua": "Three emails have been sent today."
                }
            ]
        }
    ]
}

{
    "title": "4. Negative sentences",
    "sections": [
        {
            "label": "Structure",
            "color": "rose",
            "description": "Add <strong>not</strong> after has/have: <strong>Subject + has/have + not + been + V3</strong>",
            "examples": [
                {
                    "en": "The report has not been submitted yet.",
                    "ua": "The report has not been submitted yet."
                },
                {
                    "en": "The documents have not been signed.",
                    "ua": "The documents have not been signed."
                },
                {
                    "en": "The problem has not been solved.",
                    "ua": "The problem has not been solved."
                },
                {
                    "en": "The changes have not been approved.",
                    "ua": "The changes have not been approved."
                }
            ]
        },
        {
            "label": "Abbreviated forms",
            "color": "amber",
            "description": "Colloquially: <strong>hasn't been / haven't been</strong>",
            "examples": [
                {
                    "en": "The email hasn't been sent yet.",
                    "ua": "The email hasn't been sent yet."
                },
                {
                    "en": "The tasks haven't been completed.",
                    "ua": "The tasks haven't been completed."
                },
                {
                    "en": "The decision hasn't been made.",
                    "ua": "The decision hasn't been made."
                }
            ]
        },
        {
            "label": "Typical usage with yet",
            "color": "sky",
            "description": "<strong>yet</strong> (yet) is often used in negative sentences:",
            "examples": [
                {
                    "en": "The order hasn't been delivered yet.",
                    "ua": "The order hasn't been delivered yet."
                },
                {
                    "en": "The results haven't been announced yet.",
                    "ua": "The results haven't been announced yet."
                }
            ]
        }
    ]
}

{
    "title": "5. Interrogative sentences",
    "sections": [
        {
            "label": "Yes/No question",
            "color": "blue",
            "description": "<strong>Has/Have</strong> comes first: <strong>Has/Have + Subject + been + V3?</strong>",
            "examples": [
                {
                    "en": "Has the report been finished?",
                    "ua": "Has the report been finished?"
                },
                {
                    "en": "Have the documents been signed?",
                    "ua": "Have the documents been signed?"
                },
                {
                    "en": "Has the problem been solved?",
                    "ua": "Has the problem been solved?"
                },
                {
                    "en": "Have you ever been interviewed?",
                    "ua": "Have you ever been interviewed?"
                }
            ]
        },
        {
            "label": "Wh question",
            "color": "sky",
            "description": "<strong>Wh-word + has/have + Subject + been + V3?</strong>",
            "examples": [
                {
                    "en": "How many books have been sold?",
                    "ua": "How many books have been sold?"
                },
                {
                    "en": "What has been done so far?",
                    "ua": "What has been done so far?"
                },
                {
                    "en": "Why has the meeting been cancelled?",
                    "ua": "Why has the meeting been cancelled?"
                },
                {
                    "en": "Where has the money been spent?",
                    "ua": "Where has the money been spent?"
                }
            ]
        },
        {
            "label": "Short answers",
            "color": "amber",
            "description": "Answers with <strong>Yes/No + pronoun + has/have (not)</strong>:",
            "examples": [
                {
                    "en": "Has the email been sent? — Yes, it has. / No, it hasn't.",
                    "ua": "Has the email been sent? — Yes, it has. / No, it hasn't."
                },
                {
                    "en": "Have they been informed? — Yes, they have. / No, they haven't.",
                    "ua": "Have they been informed? — Yes, they have. / No, they haven't."
                }
            ]
        }
    ]
}

{
    "title": "6. Comparison of Active vs Passive in Present Perfect",
    "intro": "How to turn an active sentence into a passive:",
    "rows": [
        {
            "en": "Active: They have completed the project.",
            "ua": "Active: They have completed the project.",
            "note": "→ Passive: The project has been completed."
        },
        {
            "en": "Active: Someone has stolen my bike.",
            "ua": "Active: Someone has stolen my bike.",
            "note": "→ Passive: My bike has been stolen."
        },
        {
            "en": "Active: The company has hired new staff.",
            "ua": "Active: The company has hired new staff.",
            "note": "→ Passive: New staff has been hired."
        },
        {
            "en": "Active: We have made a decision.",
            "ua": "Active: We have made a decision.",
            "note": "→ Passive: A decision has been made."
        }
    ],
    "warning": "📌 Time markers (just, already, yet, recently) remain!"
}

{
    "title": "7. Comparison of all Present Passive forms",
    "intro": "The difference between the three forms of the present passive tense:",
    "rows": [
        {
            "en": "Present Simple: The room is cleaned every day.",
            "ua": "Present Simple: The room is cleaned every day.",
            "note": "→ Regular action"
        },
        {
            "en": "Present Continuous: The room is being cleaned now.",
            "ua": "Present Continuous: The room is being cleaned now.",
            "note": "→ Action right now"
        },
        {
            "en": "Present Perfect: The room has been cleaned.",
            "ua": "Present Perfect: The room has been cleaned.",
            "note": "→ Completed action with result"
        }
    ],
    "warning": "📌 Present Perfect Passive emphasizes the RESULT of the action, not the process!"
}

{
    "title": "8. Time markers for the Present Perfect Passive",
    "intro": "Typical words and expressions indicating the Present Perfect:",
    "items": [
        {
            "label": "Just",
            "title": "just, recently, lately",
            "subtitle": "The report has just been submitted."
        },
        {
            "label": "Already/yet",
            "title": "already, yet, still",
            "subtitle": "The task has already been completed."
        },
        {
            "label": "Experience",
            "title": "ever, never, before",
            "subtitle": "Has this method ever been used before?"
        },
        {
            "label": "Period",
            "title": "this week/month/year, today, since, for",
            "subtitle": "Many improvements have been made this year."
        }
    ]
}

{
    "title": "9. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Skip been.",
            "wrong": "The report has completed.",
            "right": "✅ The report has been completed."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Wrong choice has/have.",
            "wrong": "The documents has been signed.",
            "right": "✅ The documents have been signed."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Confusion of been and being.",
            "wrong": "The work has being done.",
            "right": "✅ The work has been done."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Using the Past Simple instead of the Present Perfect.",
            "wrong": "The email was sent already.",
            "right": "✅ The email has already been sent."
        }
    ]
}
